def connect_wifi():
    """Connect to WiFi network."""
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(WIFI_SSID, WIFI_PASSWORD)
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
        print()
    if wlan.isconnected():
        ip = wlan.ifconfig()[0]
        print(f"Connected! IP: {ip}")
        print(f"WebSocket server will be at ws://{ip}:{WS_PORT}")
        return ip
    else:
        print("Failed to connect to WiFi")
        return None


def compute_websocket_accept(key):
    """Compute the Sec-WebSocket-Accept value."""
    GUID = "258EAFA5-E914-47DA-95CA-5AB5DC852B11"
    combined = key.strip() + GUID
    sha1_hash = hashlib.sha1(combined.encode()).digest()
    return binascii.b2a_base64(sha1_hash).decode().strip()


def parse_http_request(data):
    """Parse HTTP upgrade request and extract headers."""
    headers = {}
    lines = data.decode("utf-8").split("\r\n")
    request_line = lines[0] if lines else ""
    for line in lines[1:]:
        if ":" in line:
            key, value = line.split(":", 1)
            headers[key.strip().lower()] = value.strip()
    return request_line, headers


def perform_websocket_handshake(client_socket):
    """Perform WebSocket handshake."""
    try:
        data = client_socket.recv(1024)
        if not data:
            return False

        request_line, headers = parse_http_request(data)

        if "upgrade" not in headers.get("upgrade", "").lower():
            # Serve a simple HTML page for browser access
            serve_html_page(client_socket)
            return False

        ws_key = headers.get("sec-websocket-key", "")
        if not ws_key:
            return False

        accept_key = compute_websocket_accept(ws_key)

        response = (
            "HTTP/1.1 101 Switching Protocols\r\n"
            "Upgrade: websocket\r\n"
            "Connection: Upgrade\r\n"
            f"Sec-WebSocket-Accept: {accept_key}\r\n"
            "\r\n"
        )
        client_socket.sendall(response.encode())
        return True
    except Exception as e:
        print(f"Handshake error: {e}")
        return False


