def decode_websocket_frame(data):
    """Decode a WebSocket frame and return the payload."""
    if len(data) < 2:
        return None, None

    first_byte = data[0]
    second_byte = data[1]

    opcode = first_byte & 0x0F
    masked = (second_byte & 0x80) != 0
    payload_length = second_byte & 0x7F

    offset = 2

    if payload_length == 126:
        if len(data) < 4:
            return None, None
        payload_length = struct.unpack(">H", data[2:4])[0]
        offset = 4
    elif payload_length == 127:
        if len(data) < 10:
            return None, None
        payload_length = struct.unpack(">Q", data[2:10])[0]
        offset = 10

    if masked:
        if len(data) < offset + 4:
            return None, None
        mask_key = data[offset:offset + 4]
        offset += 4

    if len(data) < offset + payload_length:
        return None, None

    payload = data[offset:offset + payload_length]

    if masked:
        unmasked = bytearray(payload_length)
        for i in range(payload_length):
            unmasked[i] = payload[i] ^ mask_key[i % 4]
        payload = bytes(unmasked)

    return opcode, payload


def encode_websocket_frame(payload, opcode=0x01):
    """Encode data into a WebSocket frame."""
    if isinstance(payload, str):
        payload = payload.encode("utf-8")

    frame = bytearray()
    frame.append(0x80 | opcode)  # FIN + opcode

    length = len(payload)
    if length < 126:
        frame.append(length)
    elif length < 65536:
        frame.append(126)
        frame.extend(struct.pack(">H", length))
    else:
        frame.append(127)
        frame.extend(struct.pack(">Q", length))

    frame.extend(payload)
    return bytes(frame)


def send_to_client(client_socket, message):
    """Send a message to a specific WebSocket client."""
    try:
        if isinstance(message, dict):
            message = json.dumps(message)
        frame = encode_websocket_frame(message)
        client_socket.sendall(frame)
        return True
    except Exception as e:
        print(f"Send error: {e}")
        return False


def broadcast(message, exclude=None):
    """Broadcast a message to all connected clients."""
    clients_lock.acquire()
    disconnected = []
    for client in clients:
        if client != exclude:
            if not send_to_client(client, message):
                disconnected.append(client)
    for client in disconnected:
        if client in clients:
            clients.remove(client)
            try:
                client.close()
            except Exception:
                pass
    clients_lock.release()


def get_device_status():
    """Get current device status as a dictionary."""
    device_state["uptime"] = time.ticks_ms() // 1000
    # Read internal temperature sensor if available
    try:
        import esp32
        tf = esp32.raw_temperature()
        device_state["temperature"] = (tf - 32) / 1.8
    except Exception:
        device_state["temperature"] = 0.0
    return device_state.copy()


def handle_command(command, client_socket):
    """Process a JSON command and return a response."""
    action = command.get("action", "")
    device = command.get("device", "led")
    response = {"status": "ok", "action": action}

    print(f"Command: action={action}, device={device}")

    if action == "turn_on":
        if device == "led":
            led.value(1)
            device_state["led"] = True
        elif device == "relay":
            relay.value(1)
            device_state["relay"] = True
        response.update(get_device_status())

    elif action == "turn_off":
        if device == "led":
            led.value(0)
            device_state["led"] = False
        elif device == "relay":
            relay.value(0)
            device_state["relay"] = False
        response.update(get_device_status())

    elif action == "toggle":
        if device == "led":
            new_val = not device_state["led"]
            led.value(1 if new_val else 0)
            device_state["led"] = new_val
        elif device == "relay":
            new_val = not device_state["relay"]
            relay.value(1 if new_val else 0)
            device_state["relay"] = new_val
        response.update(get_device_status())

    elif action == "set_brightness":
        value = command.get("value", 0)
        value = max(0, min(100, int(value)))
        device_state["brightness"] = value
        # If using PWM for LED brightness:
        try:
            pwm = machine.PWM(machine.Pin(LED_PIN), freq=1000)
            pwm.duty(int(value * 1023 / 100))
            if value > 0:
                device_state["led"] = True
            else:
                device_state["led"] = False
        except Exception:
            pass
        response.update(get_device_status())

    elif action == "get_status":
        response.update(get_device_status())

    elif action == "set_pin":
        pin_num = command.get("pin", 2)
        pin_val = command.get("value", 0)
        try:
            p = machine.Pin(int(pin_num), machine.Pin.OUT)
            p.value(int(pin_val))
            response["pin"] = pin_num
            response["value"] = pin_val
        except Exception as e:
            response["status"] = "error"
            response["message"] = str(e)

    elif action == "restart":
        response["message"] = "Restarting in 2 seconds..."
        send_to_client(client_socket, response)
        broadcast({"event": "server_restart"}, exclude=client_socket)
        time.sleep(2)
        machine.reset()

    elif action == "ping":
        response["action"] = "pong"
        response["timestamp"] = time.ticks_ms()

    else:
        response["status"] = "error"
        response["message"] = f"Unknown action: {action}"

    return response


def handle_client(client_socket, client_addr):
    """Handle a single WebSocket client connection."""
    print(f"New connection from {client_addr}")

    # Perform WebSocket handshake
    if not perform_websocket_handshake(client_socket):
        try:
            client_socket.close()
        except Exception:
            pass
        return

    print(f"WebSocket handshake complete with {client_addr}")

    # Add to connected clients
    clients_lock.acquire()
    clients.append(client_socket)
    client_count = len(clients)
    clients_lock.release()

    # Send welcome message with current status
    welcome = {
        "event": "connected",
        "message": "Welcome to ESP32 IoT WebSocket Server",
        "clients_connected": client_count,
    }
    welcome.update(get_device_status())
    send_to_client(client_socket, welcome)

    # Notify other clients
    broadcast(
        {"event": "client_connected", "clients_connected": client_count},
        exclude=client_socket,
    )

    # Set socket timeout for reading
    client_socket.settimeout(0.5)

    buffer = b""

    try:
        while True:
            try:
                data = client_socket.recv(1024)
                if not data:
                    print(f"Client {client_addr} disconnected (no data)")
                    break

                buffer += data

                # Try to decode frame
                while len(buffer) >= 2:
                    opcode, payload = decode_websocket_frame(buffer)

                    if opcode is None:
                        # Need more data or invalid frame
                        break

                    # Calculate consumed bytes to advance buffer
                    second_byte = buffer[1]
                    frame_payload_len = second_byte & 0x7F
                    offset = 2
                    if frame_payload_len == 126:
                        actual_len = struct.unpack(">H", buffer[2:4])[0]
                        offset = 4
                    elif frame_payload_len == 127:
                        actual_len = struct.unpack(">Q", buffer[2:10])[0]
                        offset = 10
                    else:
                        actual_len = frame_payload_len

                    masked = (second_byte & 0x80) != 0
                    if masked:
                        offset += 4
                    frame_size = offset + actual_len
                    buffer = buffer[frame_size:]

                    # Handle different opcodes
                    if opcode == 0x08:  # Close frame
                        print(f"Client {client_addr} sent close frame")
                        # Send close frame back
                        close_frame = encode_websocket_frame(b"", opcode=0x08)
                        try:
                            client_socket.sendall(close_frame)
                        except Exception:
                            pass
                        raise Exception("Client closed connection")

                    elif opcode == 0x09:  # Ping
                        pong_frame = encode_websocket_frame(payload, opcode=0x0A)
                        client_socket.sendall(pong_frame)
                        continue

                    elif opcode == 0x0A:  # Pong
                        continue

                    elif opcode == 0x01:  # Text frame
                        message = payload.decode("utf-8")
                        print(f"Received from {client_addr}: {message}")

                        try:
                            command = json.loads(message)
                            response = handle_command(command, client_socket)

                            # Send response to the requesting client
                            send_to_client(client_socket, response)

                            # Broadcast state changes to all other clients
                            if command.get("action") in [
                                "turn_on", "turn_off", "toggle",
                                "set_brightness", "set_pin"
                            ]:
                                state_update = {"event": "state_changed"}
                                state_update.update(get_device_status())
                                broadcast(state_update, exclude=client_socket)

                        except ValueError:
                            error_response = {
                                "status": "error",
                                "message": "Invalid JSON format",
                            }
                            send_to_client(client_socket, error_response)
                        except Exception as e:
                            error_response = {
                                "status": "error",
                                "message": str(e),
                            }
                            send_to_client(client_socket, error_response)

            except OSError as e:
                # Timeout on recv - this is normal, just continue
                if e.args[0] == 110 or e.args[0] == 11:  # ETIMEDOUT / EAGAIN
                    continue
                else:
                    print(f"Socket error with {client_addr}: {e}")
                    break

    except Exception as e:
        print(f"Client handler error for {client_addr}: {e}")

    finally:
        # Remove client and clean up
        clients_lock.acquire()
        if client_socket in clients:
            clients.remove(client_socket)
        client_count = len(clients)
        clients_lock.release()

        try:
            client_socket.close()
        except Exception:
            pass

        print(f"Client {client_addr} disconnected. Active clients: {client_count}")

        # Notify remaining clients
        broadcast({
            "event": "client_disconnected",
            "clients_connected": client_count,
        })


def start_server():
    """Start the WebSocket server."""
    ip = connect_wifi()
    if not ip:
        print("Cannot start server without WiFi")
        return

    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind(("0.0.0.0", WS_PORT))
    server_socket.listen(5)

    print(f"WebSocket server listening on ws://{ip}:{WS_PORT}")
    print(f"Open http://{ip}:{WS_PORT} in your browser for the control panel")

    # Blink LED to indicate server is ready
    for _ in range(3):
        led.value(1)
        time.sleep(0.1)
        led.value(0)
        time.sleep(0.1)

    while True:
        try:
            client_socket, client_addr = server_socket.accept()
            # Handle each client in a new thread
            _thread.start_new_thread(handle_client, (client_socket, client_addr))
        except KeyboardInterrupt:
            print("\nShutting down server...")
            break
        except Exception as e:
            print(f"Server accept error: {e}")
            time.sleep(1)

    # Cleanup
    print("Closing all connections...")
    clients_lock.acquire()
    for client in clients:
        try:
            close_frame = encode_websocket_frame(b"", opcode=0x08)
            client.sendall(close_frame)
            client.close()
        except Exception:
            pass
    clients.clear()
    clients_lock.release()

    server_socket.close()
    print("Server stopped.")


# Entry point
if __name__ == "__main__":
    start_server()